import json
import boto3
import os
from datetime import datetime
from botocore.exceptions import ClientError

sns_client = boto3.client('sns')

def lambda_handler(event, context):
    try:
        if isinstance(event.get('body'), str):
            body = json.loads(event['body'])
        else:
            body = event.get('body', event)
        
        topic_arn = body.get('topic_arn') or event.get('topic_arn')
        message = body.get('message') or event.get('message')
        notification_type = body.get('notification_type', 'general') or event.get('notification_type', 'general')
        subject = body.get('subject') or event.get('subject')
        message_attributes = body.get('message_attributes', {}) or event.get('message_attributes', {})
        
        if not topic_arn:
            return create_response(400, {'error': 'topic_arn is required'})
        
        if not message:
            return create_response(400, {'error': 'message is required'})
        
        if not validate_topic_arn(topic_arn):
            return create_response(400, {'error': 'Invalid topic ARN format'})
        
        formatted_message = format_message(message, notification_type)
        
        sns_message_attributes = build_message_attributes(notification_type, message_attributes)
        
        response = publish_to_sns(
            topic_arn=topic_arn,
            message=formatted_message,
            subject=subject,
            message_attributes=sns_message_attributes,
            notification_type=notification_type
        )
        
        return create_response(200, {
            'message': 'Notification published successfully',
            'message_id': response['MessageId'],
            'notification_type': notification_type,
            'timestamp': datetime.utcnow().isoformat()
        })
        
    except json.JSONDecodeError as e:
        return create_response(400, {'error': f'Invalid JSON format: {str(e)}'})
    except ClientError as e:
        error_code = e.response['Error']['Code']
        error_message = e.response['Error']['Message']
        return create_response(500, {
            'error': f'AWS SNS Error: {error_code}',
            'message': error_message
        })
    except Exception as e:
        return create_response(500, {'error': f'Internal server error: {str(e)}'})


def validate_topic_arn(topic_arn):
    if not isinstance(topic_arn, str):
        return False
    
    if not topic_arn.startswith('arn:aws:sns:'):
        return False
    
    parts = topic_arn.split(':')
    if len(parts) != 6:
        return False
    
    if not parts[5]:
        return False
    
    return True


def format_message(message, notification_type):
    if notification_type == 'alert':
        return format_alert_message(message)
    elif notification_type == 'info':
        return format_info_message(message)
    elif notification_type == 'warning':
        return format_warning_message(message)
    elif notification_type == 'error':
        return format_error_message(message)
    elif notification_type == 'structured':
        return format_structured_message(message)
    else:
        return format_general_message(message)


def format_alert_message(message):
    if isinstance(message, dict):
        alert_message = {
            'default': json.dumps(message),
            'email': format_email_alert(message),
            'sms': format_sms_alert(message)
        }
        return json.dumps(alert_message)
    else:
        alert_message = {
            'default': str(message),
            'email': f"ALERT: {message}",
            'sms': f"ALERT: {message[:140]}"
        }
        return json.dumps(alert_message)


