def format_structured_message(message):
    if isinstance(message, dict):
        structured_message = {
            'default': json.dumps(message),
            'email': json.dumps(message, indent=2),
            'sms': json.dumps(message)[:140]
        }
        return json.dumps(structured_message)
    else:
        return json.dumps({'default': str(message)})


def format_general_message(message):
    if isinstance(message, dict):
        return json.dumps({'default': json.dumps(message)})
    else:
        return str(message)


def format_email_alert(message_dict):
    title = message_dict.get('title', 'Alert Notification')
    body = message_dict.get('body', '')
    details = message_dict.get('details', '')
    
    email_body = f"{title}\n\n{body}"
    if details:
        email_body += f"\n\nDetails:\n{details}"
    
    return email_body


def format_sms_alert(message_dict):
    title = message_dict.get('title', 'Alert')
    body = message_dict.get('body', '')
    sms_text = f"{title}: {body}"
    return sms_text[:140]


