def build_message_attributes(notification_type, custom_attributes):
    attributes = {
        'notification_type': {
            'DataType': 'String',
            'StringValue': notification_type
        },
        'timestamp': {
            'DataType': 'String',
            'StringValue': datetime.utcnow().isoformat()
        }
    }
    
    for key, value in custom_attributes.items():
        if isinstance(value, dict) and 'DataType' in value and 'StringValue' in value:
            attributes[sanitize_attribute_key(key)] = value
        elif isinstance(value, str):
            attributes[sanitize_attribute_key(key)] = {
                'DataType': 'String',
                'StringValue': value
            }
        elif isinstance(value, (int, float)):
            attributes[sanitize_attribute_key(key)] = {
                'DataType': 'Number',
                'StringValue': str(value)
            }
    
    return attributes


def sanitize_attribute_key(key):
    sanitized = ''.join(c if c.isalnum() or c in ['-', '_', '.'] else '_' for c in key)
    return sanitized[:256]


def publish_to_sns(topic_arn, message, subject, message_attributes, notification_type):
    publish_params = {
        'TopicArn': topic_arn,
        'MessageAttributes': message_attributes
    }
    
    if notification_type in ['alert', 'info', 'warning', 'error', 'structured']:
        publish_params['Message'] = message
        publish_params['MessageStructure'] = 'json'
    else:
        publish_params['Message'] = message
    
    if subject:
        sanitized_subject = sanitize_subject(subject)
        publish_params['Subject'] = sanitized_subject
    
    response = sns_client.publish(**publish_params)
    
    return response


def sanitize_subject(subject):
    if not isinstance(subject, str):
        subject = str(subject)
    
    sanitized = subject[:100]
    
    return sanitized


def create_response(status_code, body):
    return {
        'statusCode': status_code,
        'headers': {
            'Content-Type': 'application/json',
            'X-Content-Type-Options': 'nosniff',
            'X-Frame-Options': 'DENY',
            'Strict-Transport-Security': 'max-age=31536000; includeSubDomains'
        },
        'body': json.dumps(body)
    }